const jeunes = $('📋 Lire jeunes éligibles').all();
const token = $('🔐 Token France Travail').first().json.access_token;
const results = [];
for (const item of jeunes) {
  const j = item.json;
  const dept = j.departement || '75';
  const romes = j.codes_rome_suggeres;
  const deptCoords = {
    '06':{lat:43.7102,lon:7.2620},'13':{lat:43.2965,lon:5.3698},'33':{lat:44.8378,lon:-0.5792},
    '34':{lat:43.6110,lon:3.8767},'35':{lat:48.1173,lon:-1.6778},'44':{lat:47.2184,lon:-1.5536},
    '59':{lat:50.6292,lon:3.0573},'69':{lat:45.7640,lon:4.8357},'75':{lat:48.8566,lon:2.3522},
    '77':{lat:48.5272,lon:2.6987},'78':{lat:48.8014,lon:2.1301},'89':{lat:47.7973,lon:3.5674},
    '91':{lat:48.6293,lon:2.4396},'92':{lat:48.8283,lon:2.2399},'93':{lat:48.9100,lon:2.4200},
    '94':{lat:48.7904,lon:2.4753},'95':{lat:49.0354,lon:2.0733}
  };
  const coords = deptCoords[dept] || deptCoords['75'];
  results.push({ json: {
    jeune: j, token: token,
    ft_url: `https://api.francetravail.io/partenaire/offresdemploi/v2/offres/search?departement=${dept}&distance=20&codeROME=${romes}&range=0-49`,
    lba_url: `https://api.apprentissage.beta.gouv.fr/api/job/v1/search?latitude=${coords.lat}&longitude=${coords.lon}&radius=25&romes=${romes}`
  }});
}
return results;

// ============================================
// 🎯 MOTEUR DE SCORING v2
// 6 améliorations : contrat, temporalité, sémantique,
// entreprise nommée, niveau qualification, LBA debug
// ============================================

const ftData = $('📡 Appel France Travail').first().json;
const lbaData = $('📡 Appel Bonne Alternance').first().json;
const jeune = $('🔁 Un jeune à la fois').first().json.jeune;

const niveauFr = jeune.niveau_francais_declare || '';
const freinLangue = niveauFr.includes('Débutant') || niveauFr.includes('Non francophone');
const romesJeune = (jeune.codes_rome_suggeres || '').split(',').map(r => r.trim());
const deptJeune = jeune.departement || '';
const dispo = (jeune.disponibilite || '').toLowerCase();
const attentes = (jeune.attentes_mentor || '').toLowerCase();
const besoinsStr = (jeune.besoins || '').toLowerCase();
const classe = (jeune.classe || '').toLowerCase();

// Déterminer le type de contrat voulu
const veutCDI = besoinsStr.includes('cdd') || besoinsStr.includes('cdi') || attentes.includes('cdi');
const veutAlternance = besoinsStr.includes('alternance') || dispo.includes('alternance');
const veutStage = besoinsStr.includes('stage') || dispo.includes('stage');
const dispoImmediate = dispo.includes('immédiate') || dispo.includes('immediate');
const dispoApres = dispo.includes('après') || dispo.includes('rentrée') || dispo.includes('septembre');

// Mots-clés extraits des attentes pour matching sémantique
const motsCles = attentes.split(/[\s,;.!?]+/).filter(m => m.length > 4);

function scoreOffre(offre, source) {
  let score = 0;
  const detail = {};

  // 1. Correspondance ROME (25 pts)
  const romeOffre = source === 'FT' ? (offre.romeCode || '') : '';
  if (source === 'FT' && romesJeune.includes(romeOffre)) { score += 25; detail.rome = 25; }
  else if (source === 'LBA') { score += 20; detail.rome = 20; }
  else { detail.rome = 0; }

  // 2. Débutant accepté (20 pts)
  if (source === 'FT') {
    const debutant = offre.experienceExige === 'D' || offre.experienceExige === 'S';
    if (debutant) { score += 20; detail.debutant = 20; } else { detail.debutant = 0; }
  } else { score += 20; detail.debutant = 20; }

  // 3. Proximité géographique (15 pts)
  if (source === 'FT') {
    const deptOffre = offre.lieuTravail?.codePostal?.substring(0, 2) || '';
    if (deptOffre === deptJeune) { score += 15; detail.geo = 15; }
    else if (['75','92','93','94'].includes(deptOffre) && ['75','92','93','94'].includes(deptJeune)) { score += 10; detail.geo = 10; }
    else { detail.geo = 0; }
  } else { score += 12; detail.geo = 12; }

  // 4. Pas d'exigence français si frein langue (10 pts)
  if (freinLangue) {
    if (source === 'FT') {
      if ((offre.langues || []).length === 0) { score += 10; detail.langue = 10; } else { detail.langue = 0; }
    } else { score += 8; detail.langue = 8; }
  } else { score += 10; detail.langue = 10; }

  // 5. Pas de permis requis (5 pts)
  if (source === 'FT') {
    if ((offre.permis || []).length === 0) { score += 5; detail.permis = 5; } else { detail.permis = 0; }
  } else { score += 5; detail.permis = 5; }

  // === NOUVEAUX CRITÈRES v2 ===

  // 6. Adéquation type de contrat (10 pts / malus -15)
  if (source === 'FT') {
    const contrat = (offre.typeContratLibelle || offre.typeContrat || '').toLowerCase();
    const estInterim = contrat.includes('intérim') || contrat.includes('interim');
    const estCDI = contrat.includes('cdi');
    const estCDD = contrat.includes('cdd');
    if (veutCDI && estCDI) { score += 10; detail.contrat = 10; }
    else if (veutCDI && estCDD) { score += 3; detail.contrat = 3; }
    else if (veutCDI && estInterim) { score -= 10; detail.contrat = -10; }
    else if (veutAlternance && offre.alternance) { score += 10; detail.contrat = 10; }
    else if (veutStage) { score += 5; detail.contrat = 5; }
    else { detail.contrat = 0; }
  } else {
    if (veutAlternance) { score += 10; detail.contrat = 10; }
    else { score += 3; detail.contrat = 3; }
  }

  // 7. Matching sémantique titre vs attentes (10 pts)
  const titreLC = (source === 'FT' ? offre.intitule : offre.offer?.title || '').toLowerCase();
  const matchMots = motsCles.filter(m => titreLC.includes(m));
  if (matchMots.length >= 2) { score += 10; detail.semantique = 10; }
  else if (matchMots.length === 1) { score += 5; detail.semantique = 5; }
  else { detail.semantique = 0; }

  // 8. Entreprise nommée (3 pts)
  const entreprise = source === 'FT' ? (offre.entreprise?.nom || '') : (offre.workplace?.name || '');
  if (entreprise && entreprise !== 'Non communiqué' && entreprise.length > 2) { score += 3; detail.entreprise_nommee = 3; }
  else { detail.entreprise_nommee = 0; }

  // 9. Filtre temporalité : malus si pas dispo immédiatement et offre urgente
  if (dispoApres && !dispoImmediate) {
    if (source === 'FT') {
      const contrat = (offre.typeContratLibelle || '').toLowerCase();
      if (contrat.includes('jour') || contrat.includes('1 mois') || contrat.includes('5 jour')) {
        score -= 15; detail.temporalite = -15;
      } else { detail.temporalite = 0; }
    } else { detail.temporalite = 0; }
  } else { detail.temporalite = 0; }

  return { score: Math.max(0, score), detail };
}

// --- Scorer FT ---
const offresFT = (ftData.resultats || []).map(o => {
  const { score, detail } = scoreOffre(o, 'FT');
  return {
    source: 'France Travail', offre_id: o.id, titre: o.intitule,
    entreprise: o.entreprise?.nom || 'Non communiqué',
    lieu: o.lieuTravail?.libelle || '',
    departement_offre: o.lieuTravail?.codePostal?.substring(0, 2) || '',
    type_contrat: o.typeContratLibelle || o.typeContrat || '',
    est_alternance: o.alternance === true,
    debutant_accepte: o.experienceExige === 'D',
    url_offre: o.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${o.id}`,
    score, score_detail: detail
  };
});

// --- Scorer LBA ---
const jobs = (lbaData.jobs || []).map(j => {
  const { score, detail } = scoreOffre(j, 'LBA');
  return {
    source: 'La Bonne Alternance',
    offre_id: j.identifier?.partner_job_id || j.identifier?.id || '',
    titre: j.offer?.title || '', entreprise: j.workplace?.name || 'Non communiqué',
    lieu: j.workplace?.location?.city || '', departement_offre: '',
    type_contrat: (j.contract?.type || []).join(', '),
    est_alternance: true, debutant_accepte: true,
    url_offre: j.apply?.url || '', score, score_detail: detail
  };
});

const nbFT = (ftData.resultats || []).length;
const nbLBA = (lbaData.jobs || []).length;

const top10 = [...offresFT, ...jobs]
  .filter(o => o.score >= 55 && o.offre_id)
  .sort((a, b) => b.score - a.score)
  .slice(0, 10);

// Passer au noeud IA pour review
return [{ json: {
  jeune: jeune,
  offres: top10,
  debug: { nb_ft: nbFT, nb_lba: nbLBA, nb_apres_score: top10.length }
}}];

// ============================================
// 🧠 Préparer le prompt IA pour review
// ============================================

const data = $input.first().json;
const jeune = data.jeune;
const offres = data.offres;
const debug = data.debug;

if (offres.length === 0) {
  return [{ json: { skip: true, jeune_prenom: jeune.prenom, queries: [] } }];
}

const offresList = offres.map((o, i) => 
  `${i+1}. ${o.titre} | ${o.entreprise} | ${o.lieu} | ${o.type_contrat} | Score: ${o.score}`
).join('\n');

const prompt = `Tu es un conseiller insertion spécialisé jeunes vulnérables (ASE/MNA). Analyse ce matching et sélectionne les 3 meilleures offres.

PROFIL DU JEUNE :
- Prénom : ${jeune.prenom}
- Classe : ${jeune.classe || 'Non précisé'}
- Français : ${jeune.niveau_francais_declare || 'Non précisé'}
- Secteur visé : ${jeune.secteurs_interet}
- Disponibilité : ${jeune.disponibilite}
- Besoins : ${jeune.besoins}
- Ce qu'il/elle dit : "${(jeune.attentes_mentor || '').substring(0, 500)}"

OFFRES MATCHÉES (${debug.nb_ft} FT + ${debug.nb_lba} LBA trouvées, top ${offres.length} après scoring) :
${offresList}

RÈGLES :
- Sélectionne exactement 3 offres (ou moins si < 3 pertinentes)
- Élimine les offres incohérentes (intérim 5j pour quelqu'un qui veut un CDI, offre trop en dessous du niveau, etc.)
- Pour chaque offre retenue, écris un message court et motivant en tutoiement pour le jeune (1 phrase)

Réponds UNIQUEMENT en JSON valide, sans markdown :
{"selections": [{"rang": 1, "message": "...", "raison": "..."}]}`;

return [{ json: { prompt, jeune, offres, debug } }];

// ============================================
// 💾 Construire les INSERT avec review IA
// ============================================

const aiResponse = $('🧠 Review IA (Haiku)').first().json;
const data = $('📝 Préparer prompt IA').first().json;
const jeune = data.jeune;
const offres = data.offres;

// Parser la réponse IA
let selections = [];
try {
  const aiText = aiResponse.content?.[0]?.text || '{"selections":[]}';
  const parsed = JSON.parse(aiText);
  selections = parsed.selections || [];
} catch(e) {
  // Si l'IA échoue, garder le top 3 du scoring mathématique
  selections = offres.slice(0, 3).map((o, i) => ({ rang: i + 1, message: '', raison: 'Scoring mathématique (IA indisponible)' }));
}

const esc = (v) => {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''").substring(0, 2000) + "'";
};

const results = [];
for (const sel of selections) {
  const idx = sel.rang - 1;
  if (idx < 0 || idx >= offres.length) continue;
  const o = offres[idx];
  const message = sel.message || '';
  const raison = sel.raison || '';

  const scoreDetailWithAI = { ...o.score_detail, ai_message: message, ai_raison: raison };

  const sql = `INSERT INTO koda_matchs (jeune_id, source, offre_id, titre, entreprise, lieu, departement_offre, type_contrat, est_alternance, debutant_accepte, score, score_detail, url_offre, statut) VALUES (${esc(jeune.airtable_id)}, ${esc(o.source)}, ${esc(o.offre_id)}, ${esc(o.titre)}, ${esc(o.entreprise)}, ${esc(o.lieu)}, ${esc(o.departement_offre)}, ${esc(o.type_contrat)}, ${o.est_alternance}, ${o.debutant_accepte}, ${o.score}, '${JSON.stringify(scoreDetailWithAI).replace(/'/g, "''")}', ${esc(o.url_offre)}, 'validee_ia') ON CONFLICT (jeune_id, offre_id) DO UPDATE SET score = EXCLUDED.score, score_detail = EXCLUDED.score_detail, statut = 'validee_ia';`;
  results.push({ json: { query: sql, jeune_prenom: jeune.prenom, offre_titre: o.titre, score: o.score, ai_message: message } });
}

if (results.length === 0) {
  results.push({ json: { query: null, jeune_prenom: jeune.prenom, offre_titre: 'Aucun match retenu par IA', score: 0, ai_message: '' } });
}

return results;
